System.out.println((v ^ b) ^ b); // 42  applying b twice cancels

// All operations on bit at position k (0 = least significant)
int getBit(int x, int k)    { return (x >> k) & 1; }          // read: 0 or 1
int setBit(int x, int k)    { return x | (1 << k); }          // force to 1
int clearBit(int x, int k)  { return x & ~(1 << k); }         // force to 0
int toggleBit(int x, int k) { return x ^ (1 << k); }          // flip
boolean isSet(int x, int k) { return (x & (1 << k)) != 0; }   // test

// Update bit k to an arbitrary value v (0 or 1) branch-free
int updateBit(int x, int k, int v) {
    int mask = 1 << k;
    return (x & ~mask) | ((v << k) & mask);  // clear then set if v==1
}

// x & (-x) isolates the lowest set bit (rightmost 1)
// Works because -x == ~x + 1 flips everything above the lowest 1
int lowestSetBit(int x) { return x & (-x); }   // 0b10110 -> 0b00010

// x & (x - 1) clears the lowest set bit
// Subtracting 1 turns the lowest 1 into 0 and all bits below it into 1
int dropLowestSetBit(int x) { return x & (x - 1); }  // 0b10110 -> 0b10100

// Therefore: x is a power of two iff it has exactly one set bit
boolean isPowerOfTwo(int x) { return x > 0 && (x & (x - 1)) == 0; }

// 1) Naive: always 32 iterations
int countNaive(int x) {
    int count = 0;
    for (int i = 0; i < 32; i++) {
        count += (x >> i) & 1;
    }
    return count;
}

// 2) Brian Kernighan: iterates once PER SET BIT (faster when sparse)
int countKernighan(int x) {
    int count = 0;
    while (x != 0) {
        x &= (x - 1);   // clear lowest set bit
        count++;
    }
    return count;
}

// 3) Hardware intrinsic - compiles to a POPCNT instruction
int countBuiltin(int x) {
    return Integer.bitCount(x);   // C++: __builtin_popcount; Python: bin(x).count('1')
}

// Enumerate ALL subsets of {0..n-1} via bitmask
void allSubsets(int n) {
    for (int mask = 0; mask < (1 << n); mask++) {
        List<Integer> subset = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) subset.add(i);
        }
        // process subset
    }
}

