public int singleNumber(int[] nums) {
    int result = 0;
    for (int v : nums) {
        result ^= v;   // pairs cancel (a ^ a == 0); identity is 0
    }
    return result;
}

public int[] countBits(int n) {
    int[] ans = new int[n + 1];
    for (int i = 1; i <= n; i++) {
        // i & (i - 1) clears the lowest set bit -> a smaller, already-computed index
        ans[i] = ans[i & (i - 1)] + 1;
    }
    return ans;  // ans[0] stays 0
}
